const files = $input.first().json.files || [];
// فلترة الملفات التي لها fileName وfilePath صالحَين فقط
const validFiles = files.filter(function(f) { return f.fileName && f.filePath; });
if (validFiles.length === 0) {
  // لا توجد ملفات صالحة — أوقف التنفيذ بإرجاع مصفوفة فارغة
  return [];
}
return validFiles.map(function(f) {
  return { json: { fileName: f.fileName, filePath: f.filePath } };
});

// استخراج جميع الروابط من الملف ومعالجتها بالتوالي
const fileData = $input.first().json;
// إذا كان skip=true أو لا يوجد fileName، أوقف التنفيذ
if (fileData.skip || !fileData.fileName) return [];
// fileName وfilePath يأتيان من file_api مباشرة في response
const fileName = fileData.fileName || '';
const filePath = fileData.filePath || '';
const content = fileData.content || '';

// استخراج جميع الأسطر وتنظيفها
const lines = content.split('\n').map(function(l) { return l.trim(); }).filter(function(l) { return l.length > 0; });

// استخراج الروابط فقط
const urls = lines.filter(function(l) { return l.startsWith('http://') || l.startsWith('https://'); });

if (urls.length === 0) return [{ json: { skip: true, fileName: fileName, filePath: filePath, reason: 'لا توجد روابط في الملف' } }];

// إنتاج عنصر لكل رابط مع رقم تسلسلي
const baseName = fileName.replace(/\.(txt|url|md)$/i, '').replace(/[_\-]/g, ' ').trim();

return urls.map(function(url, i) {
  const title = urls.length > 1 ? baseName + ' (' + (i + 1) + ' من ' + urls.length + ')' : baseName;
  return { json: {
    url: url,
    title: title,
    fileName: fileName,
    filePath: filePath,
    urlIndex: i + 1,
    urlTotal: urls.length
  }};
});

const d = $input.first().json;
if (d.skip || !d.url) return [{ json: { skip: true } }];
const url = d.url;
let type = 'webpage';
if (url.indexOf('youtube.com') !== -1 || url.indexOf('youtu.be') !== -1) type = 'youtube';
else if (url.indexOf('twitter.com') !== -1 || url.indexOf('x.com') !== -1) type = 'twitter';
else if (url.indexOf('linkedin.com') !== -1) type = 'linkedin';
else if (url.indexOf('facebook.com') !== -1) type = 'facebook';
else if (url.indexOf('instagram.com') !== -1) type = 'instagram';
else if (url.indexOf('tiktok.com') !== -1) type = 'tiktok';
else if (url.indexOf('reddit.com') !== -1) type = 'reddit';
else if (/\.(mp3|wav|ogg|aac)$/i.test(url)) type = 'audio';
else if (/\.(mp4|avi|mov|mkv)$/i.test(url)) type = 'video';
else if (/\.pdf$/i.test(url)) type = 'pdf';
const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const safe = (d.title || type).replace(/[^\u0600-\u06FFa-zA-Z0-9 ]/g, '').trim().slice(0, 50);
const outputFilename = ts + '_' + safe + '.md';
// نمرر كل البيانات بما فيها fileName وfilePath
return [{ json: Object.assign({}, d, { type: type, outputFilename: outputFilename, timestamp: ts }) }];

// نحتفظ بكل بيانات typeData ونضيف بيانات Jina
const typeData = $('🔍 تحديد نوع الرابط').first().json;
const jinaData = $input.first().json;
let rawContent = jinaData.body || jinaData.data || '';

// تنظيف المحتوى حسب نوع الرابط
let cleanContent = rawContent;

if (typeData.type === 'tiktok') {
  const lines = rawContent.split('\n');
  const relevantLines = [];
  let foundDescription = false;
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!foundDescription && (line === '' || line === 'Log in' || line === 'Search' || 
        line === 'For You' || line === 'Shop' || line === 'Explore' || 
        line === 'Following' || line === 'LIVE' || line === 'Upload' || 
        line === 'Profile' || line === 'More' || line.startsWith('©'))) {
      continue;
    }
    if (!foundDescription && line.length > 10 && !line.startsWith('[![') && !line.startsWith('[**')) {
      foundDescription = true;
    }
    if (foundDescription) {
      if (line === 'Comments' || line === 'You may like' || line === 'Log in' ||
          line.startsWith('Introducing keyboard') || line.startsWith('Go to previous')) {
        break;
      }
      if (line.startsWith('[![') || (line.startsWith('[') && line.includes('ago'))) {
        continue;
      }
      if (line.length > 0) relevantLines.push(line);
    }
  }
  cleanContent = relevantLines.join('\n').trim();
  if (cleanContent.length < 50) cleanContent = rawContent.slice(0, 2000);
} else if (typeData.type === 'youtube') {
  const descMatch = rawContent.match(/Description[:\s]+([\s\S]{0,1500})/);
  cleanContent = descMatch ? descMatch[1].trim() : rawContent.slice(0, 3000);
} else {
  cleanContent = rawContent.slice(0, 4000);
}

const prompt = 'أنت مساعد متخصص في تلخيص المحتوى الرقمي. النوع: ' + typeData.type + '\nالمصدر: ' + typeData.url + '\n\nالمهمة:\n1. اكتب ملخصاً موجزاً (3-5 أسطر)\n2. استخرج 5 نقاط رئيسية\n3. حدد 5 كلمات مفتاحية\n\nالمحتوى:\n' + cleanContent.slice(0, 3000) + '\n\nأجب بالعربية بصيغة Markdown مع عناوين واضحة.';

// نمرر كل بيانات typeData مع بيانات Jina
return [{ json: Object.assign({}, typeData, { prompt: prompt, jinaContent: cleanContent }) }];

// نقرأ كل البيانات من عقدة تجهيز البرومبت (التي تحتوي على كل شيء)
const prepData = $('🧠 تجهيز البرومبت').first().json;
const aiData = $input.first().json;
const content = prepData.jinaContent || '';
const summary = aiData.response || '';
const wordCount = content.split(/\s+/).filter(function(w) { return w.length > 0; }).length;
const dateStr = new Date().toLocaleDateString('ar-SA');

// كل البيانات المهمة موجودة في prepData
const fileName = prepData.fileName || '';
const filePath = prepData.filePath || ('/data/url_inbox/' + fileName);
const ts = prepData.timestamp || new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const safe = (prepData.title || prepData.type || 'url').replace(/[^\u0600-\u06FFa-zA-Z0-9 ]/g, '').trim().slice(0, 50).replace(/\s+/g, '_');
const outputFilename = ts + '_' + safe + '.md';

const urlInfo = prepData.urlTotal > 1 ? '\n**الرابط:** ' + prepData.urlIndex + ' من ' + prepData.urlTotal : '';

const md = '---\ntitle: "' + (prepData.title || prepData.url) + '"\nurl: ' + prepData.url + '\ntype: ' + prepData.type + '\ndate: ' + ts + '\nwords: ' + wordCount + '\nsource_file: ' + fileName + '\n---\n\n# ' + (prepData.title || prepData.url) + '\n\n**المصدر:** ' + prepData.url + '  \n**النوع:** ' + prepData.type + '  \n**التاريخ:** ' + dateStr + urlInfo + '  \n**الملف الأصلي:** ' + fileName + '\n\n---\n\n## الملخص الذكي\n\n' + summary + '\n\n---\n\n## المحتوى المُنظَّف\n\n' + content + '\n';

return [{ json: {
  markdown: md,
  outputFilename: outputFilename,
  fileName: fileName,
  filePath: filePath,
  wordCount: wordCount,
  url: prepData.url,
  type: prepData.type,
  title: prepData.title,
  urlIndex: prepData.urlIndex,
  urlTotal: prepData.urlTotal,
  timestamp: ts
} }];

// نقل الملف الأصلي فقط بعد معالجة آخر رابط فيه
// البيانات تأتي من عقدة بناء Markdown عبر عقدة الحفظ
const mdData = $('📝 بناء Markdown').first().json;
const isLastUrl = mdData.urlIndex === mdData.urlTotal;

// fileName وfilePath موجودان بشكل مضمون من عقدة بناء Markdown
const fileName = mdData.fileName || '';
const filePath = mdData.filePath || ('/data/url_inbox/' + fileName);

if (!isLastUrl) {
  return [{ json: {
    skip: false,
    readyToMove: false,
    fileName: fileName,
    filePath: filePath,
    outputFilename: mdData.outputFilename,
    urlIndex: mdData.urlIndex,
    urlTotal: mdData.urlTotal,
    reason: 'انتظار معالجة باقي الروابط (' + mdData.urlIndex + '/' + mdData.urlTotal + ')'
  } }];
}

return [{ json: {
  readyToMove: true,
  fileName: fileName,
  filePath: filePath,
  outputFilename: mdData.outputFilename,
  urlIndex: mdData.urlIndex,
  urlTotal: mdData.urlTotal,
  url: mdData.url,
  type: mdData.type,
  wordCount: mdData.wordCount
} }];

const data = $input.first().json;
return [{ json: {
  success: true,
  sourceFile: data.fileName || data.moved_from || 'unknown',
  outputFile: data.outputFilename || data.outputFile || '',
  url: data.url || '',
  type: data.type || '',
  words: data.wordCount || data.words || 0,
  urlIndex: data.urlIndex,
  urlTotal: data.urlTotal,
  timestamp: new Date().toISOString()
} }];
